def classify_risk(
    output_drives_consequential_decision: bool,
    pii_in_prompts: bool,
    external_user_facing: bool,
    model_approved: bool,
    monthly_calls: int,
) -> RiskTier:
    """Deterministic risk tier based on use-case properties."""
    if output_drives_consequential_decision and external_user_facing:
        return RiskTier.CRITICAL
    if output_drives_consequential_decision or (pii_in_prompts and external_user_facing):
        return RiskTier.HIGH
    if pii_in_prompts or not model_approved or monthly_calls > 1_000_000:
        return RiskTier.MEDIUM
    return RiskTier.LOW
